                    writer.WriteNull("optionForPriceRuleConflict");

            if (createChargeRequest.AmountOption.IsSet)
                if (createChargeRequest.AmountOption.Value != null)
                    writer.WriteNumber("amount", createChargeRequest.AmountOption.Value!.Value);
                else
                    writer.WriteNull("amount");

            if (createChargeRequest.DescriptionOption.IsSet)
                if (createChargeRequest.DescriptionOption.Value != null)
                    writer.WriteString("description", createChargeRequest.Description);
                else
                    writer.WriteNull("description");

            if (createChargeRequest.ReceivablesAccountIdOption.IsSet)
                if (createChargeRequest.ReceivablesAccountIdOption.Value != null)
                    writer.WriteString("receivablesAccountId", createChargeRequest.ReceivablesAccountId);
                else
                    writer.WriteNull("receivablesAccountId");

            if (createChargeRequest.ClassIdOption.IsSet)
                if (createChargeRequest.ClassIdOption.Value != null)
                    writer.WriteString("classId", createChargeRequest.ClassId);
                else
                    writer.WriteNull("classId");

            if (createChargeRequest.BilledDateOption.IsSet)
                if (createChargeRequest.BilledDateOption.Value != null)
                    writer.WriteString("billedDate", createChargeRequest.BilledDateOption.Value!.Value.ToString(BilledDateFormat));
                else
                    writer.WriteNull("billedDate");

            if (createChargeRequest.DueDateOption.IsSet)
                if (createChargeRequest.DueDateOption.Value != null)
                    writer.WriteString("dueDate", createChargeRequest.DueDateOption.Value!.Value.ToString(DueDateFormat));
                else
                    writer.WriteNull("dueDate");

            if (createChargeRequest.OverrideItemAccountIdOption.IsSet)
                if (createChargeRequest.OverrideItemAccountIdOption.Value != null)
                    writer.WriteString("overrideItemAccountId", createChargeRequest.OverrideItemAccountId);
                else
                    writer.WriteNull("overrideItemAccountId");
        }
    }
